            switch (urgency)
            {
                case Urgency.Expired: expired.Add(entry); break;
                case Urgency.Warning: warning.Add(entry); break;
                case Urgency.Ok:      ok.Add(entry); break;
            }
        }

        return new ValidationReport(expired, warning, ok);
    }
}

