 1→// RotationValidator: Groups secrets by urgency (expired, warning, ok).
 2→// Pure function taking a list of secrets and returning a validated report.
 3→
 4→using System;
 5→using System.Collections.Generic;
 6→using System.Linq;
 7→
 8→namespace SecretRotationValidator;
 9→
10→/// <summary>Urgency level for a secret's rotation status.</summary>
11→public enum Urgency { Expired, Warning, Ok }
12→
13→/// <summary>A single secret's validation result with computed metadata.</summary>
14→public record ValidationEntry(SecretConfig Secret, Urgency Urgency, int DaysUntilExpiry);
15→
16→/// <summary>The full validation report, secrets grouped by urgency.</summary>
17→public record ValidationReport(
18→    List<ValidationEntry> Expired,
19→    List<ValidationEntry> Warning,
20→    List<ValidationEntry> Ok)
21→{
22→    /// <summary>All entries across all groups.</summary>
23→    public IEnumerable<ValidationEntry> All => Expired.Concat(Warning).Concat(Ok);
24→}
25→
26→/// <summary>
27→/// Validates a list of secrets against their rotation policies
28→/// and groups them by urgency level.
29→/// </summary>
30→public static class RotationValidator
31→{
32→    public static ValidationReport Validate(
33→        List<SecretConfig> secrets, DateTime asOf, int warningDays)
34→    {
35→        if (warningDays < 0)
36→            throw new ArgumentException("Warning days must be non-negative.", nameof(warningDays));
37→
38→        var expired = new List<ValidationEntry>();
39→        var warning = new List<ValidationEntry>();
40→        var ok = new List<ValidationEntry>();
41→
42→        foreach (var secret in secrets)
43→        {
44→            var daysUntilExpiry = secret.DaysUntilExpiry(asOf);
45→            Urgency urgency;
46→
47→            if (secret.IsExpired(asOf))
48→                urgency = Urgency.Expired;
49→            else if (secret.IsInWarningWindow(asOf, warningDays))
50→                urgency = Urgency.Warning;
51→            else
52→                urgency = Urgency.Ok;
