  3→
  4→using System;
  5→using System.Collections.Generic;
  6→using System.Globalization;
  7→using System.IO;
  8→using System.Text.Json;
  9→
 10→namespace SecretRotationValidator;
 11→
 12→/// <summary>Custom exception for configuration loading errors with clear messages.</summary>
 13→public class ConfigLoadException : Exception
 14→{
 15→    public ConfigLoadException(string message) : base(message) { }
 16→    public ConfigLoadException(string message, Exception inner) : base(message, inner) { }
 17→}
 18→
 19→public static class ConfigLoader
 20→{
 21→    /// <summary>
 22→    /// Loads secrets configuration from a JSON file path.
 23→    /// </summary>
 24→    public static List<SecretConfig> LoadFromFile(string filePath)
 25→    {
 26→        if (!File.Exists(filePath))
 27→            throw new ConfigLoadException($"Configuration file not found: {filePath}");
 28→
 29→        var json = File.ReadAllText(filePath);
 30→        return LoadFromString(json);
 31→    }
 32→
 33→    /// <summary>
 34→    /// Loads secrets configuration from a JSON string.
 35→    /// </summary>
 36→    public static List<SecretConfig> LoadFromString(string json)
 37→    {
 38→        JsonDocument doc;
 39→        try
 40→        {
 41→            doc = JsonDocument.Parse(json);
 42→        }
 43→        catch (JsonException ex)
 44→        {
 45→            throw new ConfigLoadException($"Invalid JSON: {ex.Message}", ex);
 46→        }
 47→
 48→        if (!doc.RootElement.TryGetProperty("secrets", out var secretsArray))
 49→            throw new ConfigLoadException("Configuration must contain a 'secrets' array.");
 50→
 51→        var results = new List<SecretConfig>();
 52→
 53→        for (int i = 0; i < secretsArray.GetArrayLength(); i++)
 54→        {
 55→            var element = secretsArray[i];
 56→            results.Add(ParseSecret(element, i));
 57→        }
 58→
 59→        return results;
 60→    }
 61→
 62→    private static SecretConfig ParseSecret(JsonElement element, int index)
 63→    {
 64→        // Name is required
 65→        if (!element.TryGetProperty("name", out var nameEl) ||
 66→            nameEl.ValueKind != JsonValueKind.String ||
 67→            string.IsNullOrWhiteSpace(nameEl.GetString()))
 68→        {
 69→            throw new ConfigLoadException(
 70→                $"Secret at index {index}: 'name' is required and must be a non-empty string.");
 71→        }
 72→        var name = nameEl.GetString()!;
 73→
 74→        // LastRotated is required and must be a valid date
 75→        if (!element.TryGetProperty("lastRotated", out var dateEl) ||
 76→            dateEl.ValueKind != JsonValueKind.String)
 77→        {
 78→            throw new ConfigLoadException(
 79→                $"Secret '{name}': 'lastRotated' is required and must be a date string.");
 80→        }
 81→
 82→        if (!DateTime.TryParseExact(dateEl.GetString(), "yyyy-MM-dd",
 83→                CultureInfo.InvariantCulture, DateTimeStyles.None, out var lastRotated))
 84→        {
 85→            throw new ConfigLoadException(
 86→                $"Secret '{name}': 'lastRotated' value '{dateEl.GetString()}' is not a valid date (expected yyyy-MM-dd).");
 87→        }
 88→
 89→        // RotationPolicyDays is required and must be positive
 90→        if (!element.TryGetProperty("rotationPolicyDays", out var policyEl) ||
 91→            policyEl.ValueKind != JsonValueKind.Number)
 92→        {
 93→            throw new ConfigLoadException(
 94→                $"Secret '{name}': 'rotationPolicyDays' is required and must be a number.");
 95→        }
 96→        var policyDays = policyEl.GetInt32();
 97→        if (policyDays <= 0)
 98→        {
 99→            throw new ConfigLoadException(
100→                $"Secret '{name}': 'rotationPolicyDays' must be a positive number, got {policyDays}.");
101→        }
102→
103→        // RequiredByServices defaults to empty list if not provided
104→        var services = new List<string>();
105→        if (element.TryGetProperty("requiredByServices", out var servicesEl) &&
106→            servicesEl.ValueKind == JsonValueKind.Array)
107→        {
108→            foreach (var svc in servicesEl.EnumerateArray())
109→            {
110→                if (svc.ValueKind == JsonValueKind.String)
111→                    services.Add(svc.GetString()!);
112→            }
113→        }
114→
115→        return new SecretConfig(name, lastRotated, policyDays, services);
116→    }
117→}
